class RoutePaths {
  static const login = '/login';
  static const {{route}} = '/{{route}}';
}

import 'package:flutter/material.dart';
import 'package:go_router/go_router.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import '../features/{{feature}}/views/{{feature}}_page.dart';
import '../features/{{feature}}/providers/{{feature}}_auth_provider.dart';
import 'route_paths.dart';
import '../features/auth/views/login_page.dart';

final goRouterProvider = Provider<GoRouter>((ref) {
  return GoRouter(
    initialLocation: RoutePaths.{{route}},
    redirect: (context, state) {
      final isLoggedIn = ref.read({{feature}}AuthProvider);
      final loggingIn = state.location == RoutePaths.login;

      if (!isLoggedIn && !loggingIn) return RoutePaths.login;
      if (isLoggedIn && loggingIn) return RoutePaths.{{route}};
      return null;
    },
    routes: [
      GoRoute(
        path: RoutePaths.{{route}},
        builder: (context, state) => {{Feature}}Page(),
      ),
      GoRoute(
        path: RoutePaths.login,
        builder: (context, state) => LoginPage(),
      ),
    ],
  );
});

import 'package:flutter/material.dart';

class {{Feature}}Page extends StatelessWidget {
  const {{Feature}}Page({super.key});

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('{{Feature}} Page')),
      body: Center(child: Text('Welcome to {{Feature}}!')),
    );
  }
}
